/// WASM endpoint: compile a pre-extracted polyglot function IR to a Betti topology.
///
/// This is the JS→WASM bridge for multi-language support. Because tree-sitter's
/// C runtime cannot link to wasm32-unknown-unknown (no stdio.h), the correct split is:
///
///   JS  →  web-tree-sitter parses source  →  builds PolyglotFnInput JSON
///   WASM → compile_polyglot_fn(json)       →  returns SerializedGnosisResult
use crate::ast_types::{
    BridgeExpression, BridgeNodePlan, BridgeOperation, BridgeWave, GraphAST,
};
use crate::compiler::CompileState;
use crate::polyglot_wasm_types::{
    PolyglotArgInput, PolyglotCallInput, PolyglotFnInput, PolyglotStmtInput,
};
use crate::topology::{build_bridge_ast, build_schedule, render_topology_source};
use crate::emitters::{PolyglotEmitter, PythonEmitter, RustEmitter, GoEmitter, GnotEmitter, FortranEmitter, FrankieEmitter, ForrestEmitter, LeanEmitter, GenericEmitter};
use std::collections::HashMap;
use serde::Serialize;

#[derive(Serialize)]
pub struct PolyglotGnosisResult {
    #[serde(rename = "functionName")]
    pub function_name: String,
    #[serde(rename = "language")]
    pub language: String,
    #[serde(rename = "sourceFilePath")]
    pub source_file_path: String,
    #[serde(rename = "entryNodeId")]
    pub entry_node_id: String,
    #[serde(rename = "ggSource")]
    pub gg_source: String,
    #[serde(rename = "topologySource")]
    pub topology_source: String,
    pub ast: GraphAST,
    #[serde(rename = "nodePlans")]
    pub node_plans: Vec<BridgeNodePlan>,
    pub schedule: Vec<BridgeWave>,
    #[serde(rename = "transpiledSources")]
    pub transpiled_sources: HashMap<String, String>,
}

// ── Expression lowering ────────────────────────────────────────────────────

fn lower_arg(arg: &PolyglotArgInput, state: &CompileState) -> Result<BridgeExpression, String> {
    match arg {
        PolyglotArgInput::Identifier { name, ghost_mass } => {
            if state.known_bindings.contains(name) {
                Ok(BridgeExpression::Binding { name: name.clone(), ghost_mass: ghost_mass.clone() })
            } else if state
                .input_parameter_name
                .as_deref()
                .map_or(false, |p| p == name)
            {
                Ok(BridgeExpression::Input { ghost_mass: ghost_mass.clone() })
            } else {
                Ok(BridgeExpression::Runtime { name: name.clone(), ghost_mass: ghost_mass.clone() })
            }
        }
        PolyglotArgInput::Literal { value, ghost_mass } => Ok(BridgeExpression::Literal { ghost_mass: ghost_mass.clone(), 
            value: value.clone(),
        }),
        PolyglotArgInput::Member { target, property, ghost_mass } => {
            let compiled_target = lower_arg(target, state)?;
            Ok(BridgeExpression::Member { ghost_mass: ghost_mass.clone(), 
                target: Box::new(compiled_target),
                property: property.clone(),
            })
        }
        PolyglotArgInput::Call { .. } => {
            // Nested calls should have been hoisted by the JS extractor.
            // Treat the callee name as a runtime ref as a fallback.
            Err("nested Call in arg position must be hoisted to a VarDecl by the JS extractor"
                .to_string())
        }
    }
}

// ── Statement lowering ─────────────────────────────────────────────────────

fn lower_call(
    callee: &PolyglotArgInput,
    args: &[PolyglotArgInput],
    assign_to: Option<String>,
    hint: &str,
    ghost_mass: Option<serde_json::Value>,
    state: &mut CompileState,
) -> Result<BridgeNodePlan, String> {
    let callee_expr = lower_arg(callee, state)?;
    let this_arg = if let PolyglotArgInput::Member { target, .. } = callee {
        Some(lower_arg(target, state)?)
    } else {
        None
    };
    let compiled_args: Result<Vec<_>, _> = args.iter().map(|a| lower_arg(a, state)).collect();
    let node_id = state.create_node_id("call", hint);
    Ok(BridgeNodePlan::Call { ghost_mass, 
        node_id,
        handler_label: "PolyglotBridgeCall".to_string(),
        callee: callee_expr,
        this_arg,
        args: compiled_args?,
        assign_to,
        source_location: None,
    })
}

fn lower_statement(stmt: &PolyglotStmtInput, state: &mut CompileState) -> Result<(), String> {
    match stmt {
        PolyglotStmtInput::VarDecl { bindings, init, ghost_mass } => {
            if bindings.is_empty() {
                return Err("VarDecl must have at least one binding".to_string());
            }
            let primary = &bindings[0];

            match init {
                None => {
                    // Declaration without init — emit an assign of null.
                    let node_id = state.create_node_id("assign", primary);
                    let plan = BridgeNodePlan::Assign { ghost_mass: ghost_mass.clone(), 
                        node_id,
                        handler_label: "PolyglotBridgeAssign".to_string(),
                        binding_name: primary.clone(),
                        expression: BridgeExpression::Literal { ghost_mass: None, 
                            value: serde_json::Value::Null,
                        },
                        source_location: None,
                    };
                    state.known_bindings.insert(primary.clone());
                    state.node_plans.push(plan.clone());
                    state.operations.push(BridgeOperation::Assign { plan });
                }
                Some(PolyglotArgInput::Call { callee, args, ghost_mass: call_ghost }) => {
                    let plan = lower_call(callee, args, Some(primary.clone()), primary, call_ghost.clone(), state)?;
                    state.known_bindings.insert(primary.clone());
                    state.node_plans.push(plan.clone());
                    state.operations.push(BridgeOperation::Call { plan });
                }
                Some(expr) => {
                    let compiled = lower_arg(expr, state)?;
                    let node_id = state.create_node_id("assign", primary);
                    let plan = BridgeNodePlan::Assign { ghost_mass: ghost_mass.clone(), 
                        node_id,
                        handler_label: "PolyglotBridgeAssign".to_string(),
                        binding_name: primary.clone(),
                        expression: compiled,
                        source_location: None,
                    };
                    state.known_bindings.insert(primary.clone());
                    state.node_plans.push(plan.clone());
                    state.operations.push(BridgeOperation::Assign { plan });
                }
            }
            Ok(())
        }

        PolyglotStmtInput::Call { callee, args, ghost_mass } => {
            let plan = lower_call(callee, args, None, "effect", ghost_mass.clone(), state)?;
            state.node_plans.push(plan.clone());
            state.operations.push(BridgeOperation::Call { plan });
            Ok(())
        }

        PolyglotStmtInput::Return { value, ghost_mass } => {
            match value {
                None => {
                    let node_id = state.create_node_id("return", "void");
                    let plan = BridgeNodePlan::Return { ghost_mass: ghost_mass.clone(), 
                        node_id,
                        handler_label: "PolyglotBridgeReturn".to_string(),
                        expression: BridgeExpression::Literal { ghost_mass: None, 
                            value: serde_json::Value::Null,
                        },
                        source_location: None,
                    };
                    state.node_plans.push(plan.clone());
                    state.operations.push(BridgeOperation::Return { plan });
                }
                Some(PolyglotArgInput::Call { callee, args, ghost_mass: call_ghost }) => {
                    let tmp = state.create_temp_binding("return");
                    let call_plan = lower_call(callee, args, Some(tmp.clone()), "return_call", call_ghost.clone(), state)?;
                    state.node_plans.push(call_plan.clone());
                    state.operations.push(BridgeOperation::Call { plan: call_plan });

                    let ret_id = state.create_node_id("return", "result");
                    let ret_plan = BridgeNodePlan::Return { ghost_mass: ghost_mass.clone(), 
                        node_id: ret_id,
                        handler_label: "PolyglotBridgeReturn".to_string(),
                        expression: BridgeExpression::Binding { ghost_mass: None,  name: tmp },
                        source_location: None,
                    };
                    state.node_plans.push(ret_plan.clone());
                    state.operations.push(BridgeOperation::Return { plan: ret_plan });
                }
                Some(expr) => {
                    let compiled = lower_arg(expr, state)?;
                    let node_id = state.create_node_id("return", "result");
                    let plan = BridgeNodePlan::Return { ghost_mass: ghost_mass.clone(), 
                        node_id,
                        handler_label: "PolyglotBridgeReturn".to_string(),
                        expression: compiled,
                        source_location: None,
                    };
                    state.node_plans.push(plan.clone());
                    state.operations.push(BridgeOperation::Return { plan });
                }
            }
            Ok(())
        }

        PolyglotStmtInput::Parallel { bindings, branches, ghost_mass } => {
            lower_parallel(bindings, branches, ghost_mass.clone(), state)
        }
    }
}

fn lower_parallel(
    bindings: &[String],
    branches: &[PolyglotCallInput],
    ghost_mass: Option<serde_json::Value>,
    state: &mut CompileState,
) -> Result<(), String> {
    if branches.is_empty() {
        return Ok(());
    }

    let mut branch_plans: Vec<BridgeNodePlan> = Vec::new();
    for (i, branch) in branches.iter().enumerate() {
        let hint = format!("branch_{}", i);
        let plan = lower_call(
            &branch.callee,
            &branch.args,
            branch.assign_to.clone(),
            &hint,
            branch.ghost_mass.clone(),
            state,
        )?;
        if let Some(ref assign) = branch.assign_to {
            state.known_bindings.insert(assign.clone());
        }
        state.node_plans.push(plan.clone());
        branch_plans.push(plan);
    }

    let join_id = state.create_node_id("join", "parallel");
    let join_plan = BridgeNodePlan::Join { ghost_mass: ghost_mass.clone(), 
        node_id: join_id,
        handler_label: "PolyglotBridgeJoin".to_string(),
        source_location: None,
    };
    state.node_plans.push(join_plan.clone());
    state
        .operations
        .push(BridgeOperation::Parallel {
            branches: branch_plans,
            join_plan,
        });

    // If there is a collective binding for the gathered result, emit an assign.
    if bindings.len() == 1 {
        let collective_name = &bindings[0];
        let assign_id = state.create_node_id("assign", collective_name);
        // The gathered value is an array of all branch outputs.
        let items = state
            .known_bindings
            .iter()
            .filter(|b| b.starts_with("__gg_temp_branch_"))
            .map(|b| BridgeExpression::Binding { ghost_mass: None,  name: b.clone() })
            .collect();
        let assign_plan = BridgeNodePlan::Assign { ghost_mass: ghost_mass.clone(), 
            node_id: assign_id,
            handler_label: "PolyglotBridgeAssign".to_string(),
            binding_name: collective_name.clone(),
            expression: BridgeExpression::Array { ghost_mass: None,  items },
            source_location: None,
        };
        state.known_bindings.insert(collective_name.clone());
        state.node_plans.push(assign_plan.clone());
        state
            .operations
            .push(BridgeOperation::Assign { plan: assign_plan });
    }

    Ok(())
}

// ── Public compilation function ────────────────────────────────────────────

pub fn compile_polyglot_fn_input(
    input: &PolyglotFnInput,
) -> Result<PolyglotGnosisResult, String> {
    let fn_name = &input.name;
    let file_path = input
        .file_path
        .as_deref()
        .unwrap_or("unknown")
        .to_string();
    let language = input
        .language
        .as_deref()
        .unwrap_or("unknown")
        .to_string();

    let input_param = input.params.first().cloned();
    let mut state = CompileState::new("", Default::default(), file_path.clone(), input_param, fn_name.clone());

    // Seed all declared params as known bindings.
    for p in &input.params {
        state.known_bindings.insert(p.clone());
    }

    let entry_node_id = state.create_node_id("entry", "fn");
    state.node_plans.push(BridgeNodePlan::Entry { ghost_mass: None, 
        node_id: entry_node_id.clone(),
        handler_label: "PolyglotBridgeEntry".to_string(),
        source_location: None,
    });

    for stmt in &input.body {
        lower_statement(stmt, &mut state)?;
    }

    // Ensure there's always a return.
    let has_return = state
        .operations
        .iter()
        .any(|op| matches!(op, BridgeOperation::Return { .. }));
    if !has_return {
        let ret_id = state.create_node_id("return", "void");
        let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
            node_id: ret_id,
            handler_label: "PolyglotBridgeReturn".to_string(),
            expression: BridgeExpression::Literal { ghost_mass: None, 
                value: serde_json::Value::Null,
            },
            source_location: None,
        };
        state.node_plans.push(ret_plan.clone());
        state.operations.push(BridgeOperation::Return { plan: ret_plan });
    }

    let schedule = build_schedule(&state.operations);
    let ast = build_bridge_ast(&state.node_plans, &state.operations);
    let topology_source =
        render_topology_source(fn_name, &state.node_plans, &state.operations);

    let mut transpiled_sources = HashMap::new();
    
    let py_emitter = PythonEmitter;
    transpiled_sources.insert("python".to_string(), py_emitter.emit(&state.operations, &language));
    
    let rs_emitter = RustEmitter;
    transpiled_sources.insert("rust".to_string(), rs_emitter.emit(&state.operations, &language));
    
    let go_emitter = GoEmitter;
    transpiled_sources.insert("go".to_string(), go_emitter.emit(&state.operations, &language));

    let gnot_emitter = GnotEmitter;
    transpiled_sources.insert("gnot".to_string(), gnot_emitter.emit(&state.operations, &language));

    let fortran_emitter = FortranEmitter;
    transpiled_sources.insert("fortran".to_string(), fortran_emitter.emit(&state.operations, &language));

    let frankie_emitter = FrankieEmitter;
    transpiled_sources.insert("franky".to_string(), frankie_emitter.emit(&state.operations, &language));

    let forrest_emitter = ForrestEmitter;
    transpiled_sources.insert("forrest".to_string(), forrest_emitter.emit(&state.operations, &language));

    let lean_emitter = LeanEmitter;
    transpiled_sources.insert("lean".to_string(), lean_emitter.emit(&state.operations, &language));

    let all_languages = [
        "c", "cpp", "csharp", "elixir", "fsharp", "go", "haskell",
        "java", "javascript", "kotlin", "lua", "ocaml",
        "php", "python", "ruby", "rust", "scala", "swift", "typescript", "zig"
    ];

    for lang in all_languages {
        if !transpiled_sources.contains_key(lang) {
            let generic_emitter = GenericEmitter { target_language: lang.to_string() };
            transpiled_sources.insert(lang.to_string(), generic_emitter.emit(&state.operations, &language));
        }
    }

    Ok(PolyglotGnosisResult {
        function_name: fn_name.clone(),
        language,
        source_file_path: file_path,
        entry_node_id,
        gg_source: String::new(),
        topology_source,
        ast,
        node_plans: state.node_plans,
        schedule,
        transpiled_sources,
    })
}
